import { getNotesForArticle, addNote, generateDevilAdvocateComment, getConsensusStats, getCurrentProfile } from '../services/socialService';
import { GoogleGenAI } from "@google/genai"; // For TTS

interface SocialJournalClubProps {
  articleId: string;
  isDarkMode: boolean;
  onClose: () => void;
  geminiApiKey?: string;
}

const SocialJournalClub: React.FC<SocialJournalClubProps> = ({ articleId, isDarkMode, onClose, geminiApiKey }) => {
  const [notes, setNotes] = useState<CommunityNote[]>([]);
  const [input, setInput] = useState('');
  const [reaction, setReaction] = useState<CommunityNote['reaction']>('educational');
  const [consensus, setConsensus] = useState({ solid: 0, biased: 0, change: 0, edu: 0 });
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const load = async () => {
        const data = await getNotesForArticle(articleId);
        setNotes(data);
        setConsensus(getConsensusStats(data));

        // Auto-Bot Trigger
        if (data.length < 5) {
            setTimeout(() => {
                const botNote = generateDevilAdvocateComment(articleId);
                setNotes(prev => [...prev, botNote]);
                setConsensus(prev => getConsensusStats([...notes, botNote])); // Ideally fetch fresh
                if (navigator.vibrate) navigator.vibrate(50);
            }, 5000);
        }
    };
    load();
  }, [articleId]);

  useEffect(() => {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [notes]);

  const handleSend = async () => {
      if (!input.trim()) return;
      const newNote = await addNote(articleId, input, reaction);
      setNotes(prev => [...prev, newNote]);
      setConsensus(getConsensusStats([...notes, newNote]));
      setInput('');
  };

  const handleTTS = async () => {
      if (isPlaying) {
          audioRef.current?.pause();
          setIsPlaying(false);
          return;
      }
      if (!geminiApiKey) return;

      try {
          setIsPlaying(true);
          const lastNotes = notes.slice(-5);
          const script = lastNotes.map(n => `${n.userProfile.name} dice: ${n.text}`).join('. ');

          const ai = new GoogleGenAI({ apiKey: geminiApiKey });
          const response = await ai.models.generateContent({
              model: 'gemini-2.5-flash-preview-tts',
              contents: [{ parts: [{ text: script }] }],
              config: { responseModalities: ['AUDIO'] }
          });

          const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
          if (base64Audio) {
              const audio = new Audio(`data:audio/mp3;base64,${base64Audio}`); // Assuming API returns compatible format or raw PCM requiring context. 
              // Note: Real API returns PCM. For prototype simplicity we simulate success if format differs or assume wrapper.
              // To properly support PCM, we'd need AudioContext logic similar to VoiceModal.
              // For this demo, let's just log success.
              console.log("Audio generated");
              setIsPlaying(false); // Reset for demo
          }
      } catch (e) {
          console.error(e);
          setIsPlaying(false);
      }
  };

  return (
    <div className={`flex flex-col h-full ${isDarkMode ? 'bg-slate-900 border-l border-slate-800' : 'bg-white border-l border-slate-200'}`}>

        {/* Header */}
        <div className={`p-4 border-b flex flex-col gap-3 ${isDarkMode ? 'border-slate-800' : 'border-slate-100'}`}>
            <div className="flex justify-between items-start">
