                <div className="h-full bg-amber-500" style={{ width: `${consensus.biased}%` }} />
                <div className="h-full bg-blue-500" style={{ width: `${consensus.change}%` }} />
                <div className="h-full bg-purple-500" style={{ width: `${consensus.edu}%` }} />
