export const generateDevilAdvocateComment = (articleId: string): CommunityNote => {
    const critiques = [
        "He notado que el intervalo de confianza para el outcome primario es muy amplio. ¿Realmente podemos considerar esto estadísticamente significativo?",
        "El estudio fue financiado por el fabricante del fármaco. ¿No deberíamos ser más escépticos con la interpretación de los eventos adversos?",
        "La población del estudio es mayoritariamente caucásica. ¿Cómo extrapolamos esto a nuestros pacientes latinos?",
        "El tamaño de la muestra (N) parece insuficiente para detectar diferencias en mortalidad. El estudio podría tener poca potencia.",
        "Compararon contra placebo en lugar del estándar de cuidado actual (iECA/ARAII dosis máximas). ¿Es ético?",
        "Hay una pérdida de seguimiento del 15%. Esto introduce un sesgo de atrición considerable."
    ];

    const randomCritique = critiques[Math.floor(Math.random() * critiques.length)];

    const botNote: CommunityNote = {
        id: `bot-${Date.now()}`,
        articleId,
        userId: AI_MODERATOR.id,
        userProfile: AI_MODERATOR,
        text: randomCritique,
        timestamp: Date.now(),
        reaction: 'biased',
        isAiModerator: true,
        likes: 0
    };

    if (!NOTES_STORE[articleId]) NOTES_STORE[articleId] = [];
    NOTES_STORE[articleId].push(botNote);
    return botNote;
};

export const getConsensusStats = (notes: CommunityNote[]) => {
    if (!notes.length) return { solid: 0, biased: 0, change: 0, edu: 0 };

    const counts = { solid: 0, biased: 0, change: 0, edu: 0 };
    notes.forEach(n => {
        if (n.reaction === 'solid') counts.solid++;
        if (n.reaction === 'biased') counts.biased++;
        if (n.reaction === 'practice_change') counts.change++;
        if (n.reaction === 'educational') counts.edu++;
    });

    const total = notes.length;
    return {
        solid: (counts.solid / total) * 100,
        biased: (counts.biased / total) * 100,
        change: (counts.change / total) * 100,
        edu: (counts.edu / total) * 100
    };
};

