    if (targetIndex < 0 || targetIndex >= newTopics.length) return;
    [newTopics[index], newTopics[targetIndex]] = [newTopics[targetIndex], newTopics[index]];
    setTopics(newTopics);
    if (navigator.vibrate) navigator.vibrate(10);
  };

