                        const isActive = activeTab === item.id;
                        return (
                            <button 
                                key={item.id} 
                                onPointerDown={() => {
                                    if(item.onHold) startLongPress(item.onHold);
                                    if(navigator.vibrate) navigator.vibrate(10);
                                }}
                                onPointerUp={cancelLongPress}
                                onPointerLeave={cancelLongPress}
                                onClick={item.action} 
                                className={`relative rounded-full p-3.5 transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)] active:scale-90 ${isActive ? 'text-white' : (isDarkMode ? 'text-slate-400 hover:text-white' : 'text-slate-500 hover:text-slate-900')}`}
                            >
                                {isActive && (
                                    <motion.div 
                                        layoutId="dock-active" 
                                        className="absolute inset-0 -z-10 rounded-[2rem] bg-gradient-to-tr from-blue-600 to-indigo-600 shadow-lg shadow-blue-500/30" 
                                        transition={{ type: "spring", bounce: 0.25, duration: 0.5 }} 
                                    />
